const PAGES = ["About", "Advertise", "Business", "Jobs", "Marketplace"];

function Nav({ current, setPage }) {
  const [scrolled, setScrolled] = useState(false);
  useEffect(() => {
    const h = () => setScrolled(window.scrollY > 40);
    window.addEventListener("scroll", h);
    return () => window.removeEventListener("scroll", h);
  }, []);

  return (
    <nav style={{
      position: "fixed", top: 0, left: 0, right: 0, zIndex: 200,
      display: "flex", alignItems: "center", justifyContent: "space-between",
      padding: "0 48px", height: "68px",
      background: scrolled ? "rgba(5,5,10,0.94)" : "rgba(5,5,10,0.5)",
      backdropFilter: "blur(20px)",
      borderBottom: `1px solid ${scrolled ? C.border : "transparent"}`,
      transition: "all 0.35s ease",
    }}>
      <button onClick={() => setPage("home")} style={{
        fontFamily: "'Bebas Neue', sans-serif",
        fontSize: "24px", letterSpacing: "3px",
        color: C.orange, background: "none", border: "none",
        cursor: "pointer", padding: 0,
      }}>VIBECIRCLE</button>

      <div style={{ display: "flex", gap: "8px" }}>
        {PAGES.map(p => (
          <button key={p} onClick={() => { setPage(p); window.scrollTo(0,0); }} style={{
            fontFamily: "'DM Sans', sans-serif",
            fontSize: "13px", letterSpacing: "1.5px", textTransform: "uppercase",
            color: current === p ? C.orange : C.dim,
            background: current === p ? `${C.orange}12` : "transparent",
            border: current === p ? `1px solid ${C.orange}30` : "1px solid transparent",
            borderRadius: "2px",
            padding: "7px 16px", cursor: "pointer",
            transition: "all 0.2s",
          }}
            onMouseEnter={e => { if (current !== p) { e.currentTarget.style.color = C.white; e.currentTarget.style.borderColor = "rgba(255,255,255,0.12)"; }}}
            onMouseLeave={e => { if (current !== p) { e.currentTarget.style.color = C.dim; e.currentTarget.style.borderColor = "transparent"; }}}
          >{p}</button>
        ))}
      </div>

      <button style={{
        fontFamily: "'Bebas Neue', sans-serif",
        fontSize: "13px", letterSpacing: "3px",
        padding: "9px 22px",
        background: C.orange, color: C.bg,
        border: "none", borderRadius: "2px",
        cursor: "pointer",
      }}>Join Now</button>
    </nav>
  );
}

