function MarketplacePage() {
  const [catFilter, setCatFilter] = useState("All");
  const [typeFilter, setTypeFilter] = useState("All Types");
  const [search, setSearch] = useState("");
  const [sortBy, setSortBy] = useState("Featured");
  const [activeTab, setActiveTab] = useState("Creator");
  const [applyBrand, setApplyBrand] = useState(null);
  const [postForm, setPostForm] = useState({ brand: "", category: "", budget: "", type: "", location: "", desc: "" });
  const [postSent, setPostSent] = useState(false);

  const filtered = MARKETPLACE_BRANDS.filter(b => {
    const matchCat = catFilter === "All" || b.category === catFilter;
    const matchType = typeFilter === "All Types" || b.type === typeFilter;
    const matchSearch = !search || b.name.toLowerCase().includes(search.toLowerCase()) || b.tags.some(t => t.toLowerCase().includes(search.toLowerCase()));
    return matchCat && matchType && matchSearch;
  }).sort((a, b) => {
    if (sortBy === "Budget ↑") return parseInt(b.budget) - parseInt(a.budget);
    if (sortBy === "Slots Left") return (a.slots - a.filled) - (b.slots - b.filled);
    if (sortBy === "Featured") return (b.badge ? 1 : 0) - (a.badge ? 1 : 0);
    return 0;
  });

  return (
    <div style={{ background: C.bg, color: C.white }}>
      {applyBrand && <ApplyModal brand={applyBrand} onClose={() => setApplyBrand(null)} />}

      {/* HERO */}
      <section style={{
        minHeight: "52vh",
        display: "flex", flexDirection: "column", justifyContent: "flex-end",
        padding: "140px 64px 72px",
        position: "relative", overflow: "hidden",
        background: C.bg,
      }}>
        <div style={{
          position: "absolute", inset: 0,
          backgroundImage: `linear-gradient(${C.orange}06 1px, transparent 1px), linear-gradient(90deg, ${C.orange}06 1px, transparent 1px)`,
          backgroundSize: "60px 60px",
        }} />
        <Orb top="-5%" right="5%" size={550} opacity={0.13} />
        <Orb bottom="-15%" left="25%" size={400} color={C.pink} opacity={0.08} delay="2s" />
        <Orb top="20%" left="-5%" size={300} color="#9B59FF" opacity={0.07} delay="4s" />

        <div style={{ position: "relative", zIndex: 2, maxWidth: "1100px", margin: "0 auto", width: "100%" }}>
          <div style={{ animation: "fadeUp 0.5s ease forwards", opacity: 0, marginBottom: "20px" }}>
            <Tag>Brand Marketplace</Tag>
          </div>
          <h1 style={{
            fontFamily: "'Bebas Neue', sans-serif",
            fontSize: "clamp(52px,8vw,100px)",
            lineHeight: 0.92, color: C.white,
            animation: "fadeUp 0.55s 0.08s ease forwards", opacity: 0,
            marginBottom: "24px",
          }}>
            Where brands meet<br /><span style={{ color: C.orange }}>creators who live it.</span>
          </h1>
          <p style={{
            fontFamily: "'DM Sans', sans-serif", fontSize: "clamp(16px,1.8vw,20px)",
            color: C.dim, maxWidth: "540px", lineHeight: 1.75,
            animation: "fadeUp 0.55s 0.16s ease forwards", opacity: 0,
          }}>
            Browse live brand deals, apply in seconds, and turn your city presence into paid partnerships.
          </p>

          {/* Quick stats ticker */}
          <div style={{
            display: "flex", gap: "32px", marginTop: "40px", flexWrap: "wrap",
            animation: "fadeUp 0.55s 0.24s ease forwards", opacity: 0,
          }}>
            {[["140+", "Active Deals"], ["3,200+", "Creators Matched"], ["$2.4M+", "Paid Out"], ["48hrs", "Avg Response"]].map(([v, l]) => (
              <div key={l}>
                <div style={{ fontFamily: "'Bebas Neue', sans-serif", fontSize: "clamp(22px,2.5vw,30px)", color: C.orange, lineHeight: 1 }}>{v}</div>
                <div style={{ fontFamily: "'DM Sans', sans-serif", fontSize: "11px", letterSpacing: "1.5px", color: C.dimmer, textTransform: "uppercase", marginTop: "4px" }}>{l}</div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* ROLE TOGGLE */}
      <div style={{ background: C.bg2, borderTop: `1px solid ${C.border}`, borderBottom: `1px solid ${C.border}` }}>
        <div style={{ maxWidth: "1100px", margin: "0 auto", padding: "0 64px", display: "flex", gap: 0 }}>
          {["Creator", "Brand"].map(tab => (
            <button key={tab} onClick={() => setActiveTab(tab)} style={{
              fontFamily: "'Bebas Neue', sans-serif", fontSize: "14px", letterSpacing: "3px",
              padding: "20px 32px", background: "none",
              color: activeTab === tab ? C.orange : C.dimmer,
              border: "none",
              borderBottom: `2px solid ${activeTab === tab ? C.orange : "transparent"}`,
              cursor: "pointer", transition: "all 0.2s",
            }}>{tab === "Creator" ? "I'm a Creator" : "I'm a Brand"}</button>
          ))}
        </div>
      </div>

      {activeTab === "Creator" ? (
        <>
          {/* SEARCH + FILTERS */}
          <section style={{ padding: "48px 64px 0", background: C.bg2 }}>
            <div style={{ maxWidth: "1100px", margin: "0 auto" }}>
              {/* Search bar */}
              <div style={{ position: "relative", marginBottom: "28px" }}>
                <span style={{ position: "absolute", left: "18px", top: "50%", transform: "translateY(-50%)", color: "rgba(255,255,255,0.25)", fontSize: "16px" }}>🔍</span>
                <input
                  placeholder="Search by brand name or vibe tag..."
                  value={search}
                  onChange={e => setSearch(e.target.value)}
                  style={{
                    width: "100%", background: "rgba(255,255,255,0.04)",
                    border: "1px solid rgba(255,255,255,0.1)", borderRadius: "2px",
                    padding: "16px 20px 16px 48px",
                    fontFamily: "'DM Sans', sans-serif", fontSize: "15px", color: C.white, outline: "none",
                    transition: "border-color 0.2s",
                  }}
                  onFocus={e => e.target.style.borderColor = C.orange}
                  onBlur={e => e.target.style.borderColor = "rgba(255,255,255,0.1)"}
                />
              </div>

              {/* Filter bar */}
              <div style={{ display: "flex", gap: "12px", flexWrap: "wrap", alignItems: "center", paddingBottom: "28px" }}>
                <div style={{ display: "flex", gap: "6px", flexWrap: "wrap", flex: 1 }}>
                  {MKT_CATEGORIES.map(c => (
                    <button key={c} onClick={() => setCatFilter(c)} style={{
                      fontFamily: "'DM Sans', sans-serif", fontSize: "12px",
                      padding: "7px 14px", borderRadius: "2px", cursor: "pointer",
                      background: catFilter === c ? C.orange : "rgba(255,255,255,0.04)",
                      color: catFilter === c ? C.bg : C.dim,
                      border: catFilter === c ? "none" : "1px solid rgba(255,255,255,0.1)",
                      transition: "all 0.2s",
                    }}>{c}</button>
                  ))}
                </div>
                <select value={sortBy} onChange={e => setSortBy(e.target.value)} style={{
                  background: "rgba(255,255,255,0.04)", border: "1px solid rgba(255,255,255,0.1)",
                  color: C.dim, padding: "8px 14px", borderRadius: "2px",
                  fontFamily: "'DM Sans', sans-serif", fontSize: "12px", outline: "none", cursor: "pointer",
                }}>
                  {["Featured", "Budget ↑", "Slots Left"].map(s => <option key={s} value={s} style={{ background: "#0C0C18" }}>{s}</option>)}
                </select>
              </div>
            </div>
          </section>

          {/* BRAND GRID */}
          <section style={{ padding: "32px 64px 100px", background: C.bg2 }}>
            <div style={{ maxWidth: "1100px", margin: "0 auto" }}>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "28px" }}>
                <p style={{ fontFamily: "'DM Sans', sans-serif", fontSize: "14px", color: C.dimmer }}>
                  Showing <span style={{ color: C.orange }}>{filtered.length}</span> deals
                </p>
              </div>

              {filtered.length > 0 ? (
                <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(320px,1fr))", gap: "20px" }}>
                  {filtered.map((brand, i) => (
                    <Reveal key={brand.id} delay={i * 0.05}>
                      <BrandCard brand={brand} onApply={setApplyBrand} />
                    </Reveal>
                  ))}
                </div>
              ) : (
                <div style={{ textAlign: "center", padding: "80px", color: C.dimmer }}>
                  <div style={{ fontSize: "40px", marginBottom: "16px" }}>🔍</div>
                  <div style={{ fontFamily: "'Bebas Neue', sans-serif", fontSize: "24px", color: C.white, marginBottom: "8px" }}>No deals found</div>
                  <p style={{ fontFamily: "'DM Sans', sans-serif", fontSize: "14px" }}>Try adjusting your filters or search term.</p>
                </div>
              )}
            </div>
          </section>

          {/* HOW IT WORKS — CREATOR */}
          <section style={{ padding: "100px 64px", background: C.bg, position: "relative", overflow: "hidden" }}>
            <Orb top="10%" right="-8%" size={450} opacity={0.1} delay="1s" />
            <div style={{ maxWidth: "1100px", margin: "0 auto" }}>
              <Reveal style={{ marginBottom: "64px" }}>
                <Tag>For Creators</Tag>
                <h2 style={{ fontFamily: "'Bebas Neue', sans-serif", fontSize: "clamp(36px,5vw,58px)", color: C.white, lineHeight: 1, marginTop: "16px" }}>
                  Four steps to your<br /><span style={{ color: C.orange }}>first brand deal.</span>
                </h2>
              </Reveal>
              <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(220px,1fr))", gap: "20px" }}>
                {HOW_IT_WORKS_CREATOR.map((s, i) => (
                  <Reveal key={i} delay={i * 0.1}>
                    <div style={{
                      padding: "36px 28px",
                      background: i % 2 === 0 ? "rgba(255,107,0,0.04)" : "rgba(255,255,255,0.02)",
                      border: `1px solid ${i % 2 === 0 ? C.orange + "20" : "rgba(255,255,255,0.07)"}`,
                      borderRadius: "4px", height: "100%",
                    }}>
                      <div style={{ fontFamily: "'Bebas Neue', sans-serif", fontSize: "11px", letterSpacing: "3px", color: C.orange, marginBottom: "12px" }}>{s.n}</div>
                      <div style={{ fontSize: "28px", marginBottom: "14px" }}>{s.icon}</div>
                      <div style={{ fontFamily: "'Bebas Neue', sans-serif", fontSize: "20px", color: C.white, marginBottom: "12px" }}>{s.title}</div>
                      <div style={{ fontFamily: "'DM Sans', sans-serif", fontSize: "14px", color: C.dim, lineHeight: 1.7 }}>{s.desc}</div>
                    </div>
                  </Reveal>
                ))}
              </div>
            </div>
          </section>
        </>
      ) : (
        /* BRAND TAB — POST A DEAL */
        <>
          <section style={{ padding: "80px 64px", background: C.bg2 }}>
            <div style={{ maxWidth: "1100px", margin: "0 auto", display: "grid", gridTemplateColumns: "1fr 1fr", gap: "80px", alignItems: "start" }}>
              <div>
                <Reveal>
                  <Tag>For Brands</Tag>
                  <h2 style={{ fontFamily: "'Bebas Neue', sans-serif", fontSize: "clamp(36px,5vw,58px)", color: C.white, lineHeight: 1, margin: "20px 0 24px" }}>
                    Post a deal.<br /><span style={{ color: C.orange }}>Find your creators.</span>
                  </h2>
                  <p style={{ fontFamily: "'DM Sans', sans-serif", fontSize: "17px", color: C.dim, lineHeight: 1.8, marginBottom: "40px" }}>
                    Access thousands of verified creators who are already embedded in your target cities and culture niches. No agencies, no overhead — direct creative partnerships.
                  </p>
                </Reveal>
                <div style={{ display: "flex", flexDirection: "column", gap: "16px" }}>
                  {HOW_IT_WORKS_BRAND.map((s, i) => (
                    <Reveal key={i} delay={i * 0.08}>
                      <div style={{ display: "flex", gap: "16px", alignItems: "flex-start" }}>
                        <div style={{
                          width: "36px", height: "36px", borderRadius: "2px", flexShrink: 0,
                          background: "rgba(255,107,0,0.12)", border: `1px solid ${C.orange}30`,
                          display: "flex", alignItems: "center", justifyContent: "center",
                          fontFamily: "'Bebas Neue', sans-serif", fontSize: "14px", color: C.orange,
                        }}>{s.n}</div>
                        <div>
                          <div style={{ fontFamily: "'Bebas Neue', sans-serif", fontSize: "18px", color: C.white, marginBottom: "4px" }}>{s.icon} {s.title}</div>
                          <div style={{ fontFamily: "'DM Sans', sans-serif", fontSize: "14px", color: C.dim, lineHeight: 1.6 }}>{s.desc}</div>
                        </div>
                      </div>
                    </Reveal>
                  ))}
                </div>
              </div>

              {/* Post form */}
              <Reveal delay={0.1}>
                <div style={{
                  padding: "44px",
                  background: "rgba(255,255,255,0.02)",
                  border: `1px solid ${C.border}`,
                  borderRadius: "4px",
                  position: "sticky", top: "80px",
                }}>
                  {postSent ? (
                    <div style={{ textAlign: "center", padding: "40px 0" }}>
                      <div style={{ fontSize: "48px", marginBottom: "16px" }}>🎯</div>
                      <div style={{ fontFamily: "'Bebas Neue', sans-serif", fontSize: "32px", color: C.orange, marginBottom: "12px" }}>Deal Posted!</div>
                      <p style={{ fontFamily: "'DM Sans', sans-serif", fontSize: "15px", color: C.dim, lineHeight: 1.7 }}>
                        Your campaign is under review and will go live within 24 hours. Creators will start applying soon.
                      </p>
                      <button onClick={() => { setPostSent(false); setPostForm({ brand: "", category: "", budget: "", type: "", location: "", desc: "" }); }} style={{
                        fontFamily: "'Bebas Neue', sans-serif", fontSize: "14px", letterSpacing: "2px",
                        padding: "12px 28px", background: C.orange, color: C.bg,
                        border: "none", borderRadius: "2px", cursor: "pointer", marginTop: "28px",
                      }}>Post Another Deal</button>
                    </div>
                  ) : (
                    <>
                      <div style={{ fontFamily: "'Bebas Neue', sans-serif", fontSize: "24px", color: C.white, marginBottom: "28px" }}>
                        Post a Campaign Deal
                      </div>
                      <div style={{ display: "flex", flexDirection: "column", gap: "14px" }}>
                        {[["brand", "Brand Name"], ["budget", "Budget Range (e.g. $500–$2K)"], ["location", "Target Location(s)"]].map(([k, ph]) => (
                          <input key={k} placeholder={ph} value={postForm[k]} onChange={e => setPostForm({ ...postForm, [k]: e.target.value })}
                            style={{
                              background: "rgba(255,255,255,0.04)", border: "1px solid rgba(255,255,255,0.1)",
                              borderRadius: "2px", padding: "14px 16px",
                              fontFamily: "'DM Sans', sans-serif", fontSize: "14px", color: C.white, outline: "none",
                              transition: "border-color 0.2s",
                            }}
                            onFocus={e => e.target.style.borderColor = C.orange}
                            onBlur={e => e.target.style.borderColor = "rgba(255,255,255,0.1)"}
                          />
                        ))}
                        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "12px" }}>
                          <select value={postForm.category} onChange={e => setPostForm({ ...postForm, category: e.target.value })} style={{ background: "rgba(255,255,255,0.04)", border: "1px solid rgba(255,255,255,0.1)", color: postForm.category ? C.white : "rgba(255,255,255,0.25)", padding: "14px 16px", borderRadius: "2px", fontFamily: "'DM Sans', sans-serif", fontSize: "14px", outline: "none", cursor: "pointer" }}>
                            <option value="" style={{ background: "#0C0C18" }}>Category</option>
                            {MKT_CATEGORIES.slice(1).map(c => <option key={c} value={c} style={{ background: "#0C0C18" }}>{c}</option>)}
                          </select>
                          <select value={postForm.type} onChange={e => setPostForm({ ...postForm, type: e.target.value })} style={{ background: "rgba(255,255,255,0.04)", border: "1px solid rgba(255,255,255,0.1)", color: postForm.type ? C.white : "rgba(255,255,255,0.25)", padding: "14px 16px", borderRadius: "2px", fontFamily: "'DM Sans', sans-serif", fontSize: "14px", outline: "none", cursor: "pointer" }}>
                            <option value="" style={{ background: "#0C0C18" }}>Campaign Type</option>
                            {MKT_TYPES.slice(1).map(t => <option key={t} value={t} style={{ background: "#0C0C18" }}>{t}</option>)}
                          </select>
                        </div>
                        <textarea placeholder="Describe your campaign and what you're looking for in a creator..." rows={4} value={postForm.desc} onChange={e => setPostForm({ ...postForm, desc: e.target.value })}
                          style={{
                            background: "rgba(255,255,255,0.04)", border: "1px solid rgba(255,255,255,0.1)",
                            borderRadius: "2px", padding: "14px 16px",
                            fontFamily: "'DM Sans', sans-serif", fontSize: "14px", color: C.white, outline: "none", resize: "vertical",
                            transition: "border-color 0.2s",
                          }}
                          onFocus={e => e.target.style.borderColor = C.orange}
                          onBlur={e => e.target.style.borderColor = "rgba(255,255,255,0.1)"}
                        />
                        <button onClick={() => postForm.brand && postForm.budget ? setPostSent(true) : null} style={{
                          fontFamily: "'Bebas Neue', sans-serif", fontSize: "15px", letterSpacing: "3px",
                          padding: "16px", background: C.orange, color: C.bg,
                          border: "none", borderRadius: "2px", cursor: "pointer",
                          transition: "box-shadow 0.2s",
                        }}
                          onMouseEnter={e => e.target.style.boxShadow = `0 10px 30px ${C.orange}40`}
                          onMouseLeave={e => e.target.style.boxShadow = "none"}
                        >Post My Deal</button>
                        <p style={{ fontFamily: "'DM Sans', sans-serif", fontSize: "11px", color: C.dimmer, textAlign: "center" }}>
                          Enterprise plans: partners@vibecircle.com
                        </p>
                      </div>
                    </>
                  )}
                </div>
              </Reveal>
            </div>
          </section>
        </>
      )}

      {/* BOTTOM CTA BAND */}
      <div style={{ background: C.orange, padding: "24px 64px", overflow: "hidden" }}>
        <div style={{ display: "flex", animation: "marquee 22s linear infinite", whiteSpace: "nowrap" }}>
          {[...Array(4)].map((_, x) =>
            ["Brand Deals", "·", "Creator Matching", "·", "Real Payments", "·", "City Culture", "·", "Authentic Collabs", "·"].map((w, i) => (
              <span key={`${x}-${i}`} style={{ fontFamily: "'Bebas Neue', sans-serif", fontSize: "15px", letterSpacing: "3px", color: "rgba(5,5,10,0.65)", marginRight: "28px" }}>{w}</span>
            ))
          )}
        </div>
      </div>
    </div>
  );
}

// ─── ROOT APP ─────────────────────────────────────────────────────────────────
export default function App() {
  const [page, setPage] = useState("home");

  const PageMap = {
    home: <HomePage setPage={setPage} />,
    About: <AboutPage />,
    Advertise: <AdvertisePage />,
    Business: <BusinessPage />,
    Jobs: <JobsPage />,
    Marketplace: <MarketplacePage />,
  };

  return (
    <>
      <style>{GLOBAL_CSS}</style>
      <Nav current={page} setPage={setPage} />
      <main>{PageMap[page] || PageMap.home}</main>
      {page !== "home" && <Footer setPage={setPage} />}
    </>
  );
}
